steps.content:
{
  "success": true,
  "data": "{
  "query": "CAISO regulation service participation requirements regulation ancillary services eligibility telemetry AGC minimum size performance score 'regulation' 'California ISO' 'participation requirements' 'ancillary services' BPM regulation",
  "num_results": 10,
  "results": [
    {
